+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+export type WindowOrderBy = SQLWrapper;
+export interface WindowSpec {
+	partitionBy?: WindowOrderBy | WindowOrderBy[];
+	orderBy?: WindowOrderBy | WindowOrderBy[];
+	frame?: WindowFrame;
+}
+
+type BoundaryKind = 'unbounded preceding' | 'current row' | 'unbounded following' | 'preceding' | 'following';
+export interface WindowBoundary { readonly kind: BoundaryKind; readonly value?: number; }
+export interface WindowFrame { readonly mode: 'rows' | 'range'; readonly from: WindowBoundary; readonly to?: WindowBoundary; }
+
+export const unboundedPreceding: WindowBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowBoundary = { kind: 'unbounded following' };
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	return { kind: name, value };
+}
+export function preceding(value: number): WindowBoundary { return positionalBoundary('preceding', value); }
+export function following(value: number): WindowBoundary { return positionalBoundary('following', value); }
+
+const boundaryOrder: Record<BoundaryKind, number> = {
+	'unbounded preceding': 0, preceding: 1, 'current row': 2, following: 3, 'unbounded following': 4,
+};
+function makeFrame(mode: WindowFrame['mode'], frame: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	if (boundaryOrder[frame.from.kind] > boundaryOrder[frame.to?.kind ?? frame.from.kind]) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { mode, ...frame };
+}
+export function rows(frame: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame { return makeFrame('rows', frame); }
+export function range(frame: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame { return makeFrame('range', frame); }
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	return boundary.value === undefined ? sql.raw(boundary.kind) : sql.raw(`${boundary.value} ${boundary.kind}`);
+}
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	if (spec.orderBy) parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	if (spec.frame) {
+		const frame = spec.frame;
+		parts.push(frame.to
+			? sql`${sql.raw(frame.mode)} between ${boundarySql(frame.from)} and ${boundarySql(frame.to)}`
+			: sql`${sql.raw(frame.mode)} ${boundarySql(frame.from)}`);
+	}
+	return sql.join(parts, sql` `);
+}
+
+type Value<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer U> ? U : unknown;
+class WindowFunction<T> implements SQLWrapper {
