+	oSQLFrame?(): never;
+	oSQLOrder?(): never;
+	oSQLPartition?(): never;
+	oSQLAggregate?(): never;
+	/** Applies an inline specification or a named window. */
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string' ? sql`${this.expression} over ${sql.identifier(spec)}` : sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+function window<T>(name: string, args: SQL[]): WindowFunction<T> { return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`); }
+function positive(name: string, value: number): void { if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer, received ${value}`); }
+function literal(value: number): SQL { return sql.raw(String(value)); }
+
+export function rowNumber(): WindowFunction<number> { return window('row_number', []); }
+export function rank(): WindowFunction<number> { return window('rank', []); }
+export function denseRank(): WindowFunction<number> { return window('dense_rank', []); }
+export function ntile(buckets: number): WindowFunction<number> { positive('ntile', buckets); return window('ntile', [literal(buckets)]); }
+export function percentRank(): WindowFunction<number> { return window('percent_rank', []); }
+export function cumeDist(): WindowFunction<number> { return window('cume_dist', []); }
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null>;
+export function lag<T extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: SQLWrapper): WindowFunction<Value<T>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> { return window('lag', [value, ...(offset === undefined ? [] : [literal(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null>;
+export function lead<T extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: SQLWrapper): WindowFunction<Value<T>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> { return window('lead', [value, ...(offset === undefined ? [] : [literal(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> { return window('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> { return window('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<Value<T> | null> { positive('nthValue', nth); return window('nth_value', [value, literal(nth)]); }
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return window('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return window('avg', [value]); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> { return window('min', [value]); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> { return window('max', [value]); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return window('count', [value ?? sql.raw('*')]); }
