 * ```
 *
 * @see avg to get the average of all non-null values in `expression`, including duplicates
 */
export function avgDistinct(expression: SQLWrapper): SQL<string | null> {
	return sql`avg(distinct ${expression})`.mapWith(String);
}

/**
